// src/components/common/Header.jsx
import React, { useContext, useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';
import { CartContext } from '../../context/CartContext';
import { productAPI, categoryAPI } from '../../api';

const Header = () => {
  const { user, logout } = useContext(AuthContext);
  const { cartItems } = useContext(CartContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [categories, setCategories] = useState([]);
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  useEffect(() => {
    fetchCategories();

    const params = new URLSearchParams(location.search);
    setSearchTerm(params.get('q') || '');
    setSelectedCategory(params.get('category') || 'all');
  }, [location.search]);

  const fetchCategories = async () => {
    try {
      const response = await categoryAPI.getCategories();
      if (response.data && Array.isArray(response.data)) {
        setCategories(response.data);
      }
    } catch (error) {
      console.error('Error fetching categories:', error);
      setCategories([
        { _id: 'hoa-cuoi', name: 'Hoa cưới', slug: 'hoa-cuoi' },
        { _id: 'hoa-sinh-nhat', name: 'Hoa sinh nhật', slug: 'hoa-sinh-nhat' },
        { _id: 'hoa-chuc-mung', name: 'Hoa chúc mừng', slug: 'hoa-chuc-mung' },
        { _id: 'hoa-valentine', name: 'Hoa Valentine', slug: 'hoa-valentine' }
      ]);
    }
  };

  const fetchSuggestions = async (term) => {
    if (term.length < 2) {
      setSuggestions([]);
      return;
    }
    try {
      const response = await productAPI.getSearchSuggestions(term);
      setSuggestions(response.data?.suggestions || []);
    } catch (error) {
      console.error('Error fetching suggestions:', error);
      setSuggestions([]);
    }
  };

  const handleSearchInputChange = (e) => {
    const value = e.target.value;
    setSearchTerm(value);

    clearTimeout(window.searchTimeout);
    window.searchTimeout = setTimeout(() => {
      fetchSuggestions(value);
      setShowSuggestions(value.length > 0);
    }, 300);
  };

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    performSearch();
  };

  const performSearch = () => {
    const params = new URLSearchParams();
    if (searchTerm.trim()) params.set('q', searchTerm.trim());
    if (selectedCategory !== 'all') params.set('category', selectedCategory);

    navigate(`/product${params.toString() ? `?${params.toString()}` : ''}`);
    setShowSuggestions(false);
  };

  const selectSuggestion = (suggestion) => {
    setSearchTerm(suggestion);
    setShowSuggestions(false);

    const params = new URLSearchParams();
    params.set('q', suggestion);
    if (selectedCategory !== 'all') params.set('category', selectedCategory);

    navigate(`/product?${params.toString()}`);
  };

  return (
    <>
      {/* Top Bar */}
      <div className="bg-secondary text-dark py-2 px-4 flex justify-between w-full text-sm font-sans">
        <p className="italic">DDT Flower Shop</p>
        <div className="flex gap-4">
          {user ? (
            <>
              <Link to="/profile" className="hover:text-primary">{user.name}</Link>
              {user.role === 'admin' && (
                <Link to="/admin/dashboard" className="hover:text-primary">Quản trị</Link>
              )}
              <button onClick={logout} className="hover:text-primary">Đăng xuất</button>
            </>
          ) : (
            <Link to="/login" className="hover:text-primary">Tài khoản</Link>
          )}
        </div>
      </div>

      {/* Header Main */}
      <header className="bg-light shadow-md p-4">
        <div className="flex justify-between items-center">
          {/* Logo + Tên */}
          <div className="flex items-center gap-3">
            <Link to="/">
              <img src="/DTP.png" alt="Logo" className="h-16 w-auto rounded-full shadow-sm" />
            </Link>
            <span className="font-serif text-2xl text-dark">Petals & Poetry</span>
          </div>

          {/* Search Box */}
          <div className="relative w-full max-w-md mx-5">
            <form
              onSubmit={handleSearchSubmit}
              className="flex items-center border border-primary rounded-full bg-white overflow-hidden shadow-sm"
            >
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="h-10 bg-secondary px-3 text-sm focus:outline-none rounded-l-full"
              >
                <option value="all">Tất cả</option>
                {categories.map((category) => (
                  <option key={category._id} value={category.slug}>{category.name}</option>
                ))}
              </select>

              <input
                type="text"
                value={searchTerm}
                onChange={handleSearchInputChange}
                onFocus={() => setShowSuggestions(searchTerm.length > 0)}
                placeholder="Tìm kiếm hoa..."
                className="flex-1 h-10 px-3 text-base focus:outline-none font-sans"
              />

              <button
                type="submit"
                className="h-10 bg-primary text-white px-4 flex items-center justify-center hover:opacity-90 transition rounded-r-full"
              >
                <i className="fas fa-search"></i>
              </button>
            </form>

            {/* Suggestions */}
            {showSuggestions && suggestions.length > 0 && (
              <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-b-lg shadow-lg z-50 max-h-60 overflow-y-auto">
                {suggestions.map((s, i) => (
                  <div
                    key={i}
                    onClick={() => selectSuggestion(s)}
                    className="px-4 py-2 hover:bg-gray-100 cursor-pointer border-b border-gray-100 last:border-b-0"
                  >
                    <div className="flex items-center">
                      <i className="fas fa-search text-gray-400 mr-2"></i>
                      <span>{s}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Popular keywords fallback */}
            {showSuggestions && suggestions.length === 0 && searchTerm.length > 0 && (
              <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-b-lg shadow-lg z-50">
                <div className="px-4 py-2 text-gray-500 text-sm border-b">
                  Từ khóa phổ biến:
                </div>
                {['hoa hồng', 'hoa sinh nhật', 'hoa cưới', 'hoa valentine'].map((kw, i) => (
                  <div
                    key={i}
                    onClick={() => selectSuggestion(kw)}
                    className="px-4 py-2 hover:bg-gray-100 cursor-pointer border-b border-gray-100 last:border-b-0"
                  >
                    <div className="flex items-center">
                      <i className="fas fa-fire text-orange-400 mr-2"></i>
                      <span>{kw}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Cart */}
          <Link
            to="/cart"
            className="no-underline bg-primary text-white px-5 py-2 rounded-full text-lg font-bold flex items-center gap-2 relative hover:opacity-90 transition-all duration-300"
          >
            <i className="fas fa-shopping-cart"></i> Giỏ hàng
            {cartCount > 0 && (
              <span className="absolute -top-1 -right-2 bg-dark text-white text-xs px-2 py-1 rounded-full font-bold">
                {cartCount}
              </span>
            )}
          </Link>
        </div>
      </header>
    </>
  );
};

export default Header;
